// n8n Error Trigger からのデータを整形 + 通知すべきか判定
// 通知条件:
//  - mode が 'trigger' (= cron / webhook など本番自動実行) の場合のみ
//  - mode == 'manual' (UI から手動 Execute) はスキップ

const e = $input.first().json;
const exec = e.execution || {};
const wf = e.workflow || {};
const err = exec.error || {};
const lastNode = err.node && err.node.name ? err.node.name : '(unknown)';
const mode = exec.mode || '(unknown)';
const execId = exec.id || '?';
const execUrl = exec.url || `https://campwill.app.n8n.cloud/workflow/${wf.id}/executions/${execId}`;

const rawMessage = err.message || '(no message)';
const desc = err.description || '';
const httpCode = err.httpCode || '';
const rawDetail = (err.messages && err.messages[0]) ? String(err.messages[0]).substring(0, 500) : '';

const now = new Date();
const jst = new Date(now.getTime() + 9 * 60 * 60 * 1000).toISOString().replace('T', ' ').substring(0, 19);

const shouldNotify = mode === 'trigger' || mode === 'webhook' || mode === 'retry';

return [{
  json: {
    should_notify: shouldNotify,
    workflow_name: wf.name || '(unknown)',
    workflow_id: wf.id || '',
    execution_id: execId,
    execution_url: execUrl,
    failed_node: lastNode,
    mode: mode,
    error_message: rawMessage,
    error_description: desc,
    http_code: httpCode,
    raw_detail: rawDetail,
    timestamp_jst: jst,
    slack_text: `🚨 *n8n Workflow Failed*\n*Workflow*: ${wf.name || '?'}\n*Failed node*: ${lastNode}\n*Error*: ${rawMessage}${httpCode ? ' (HTTP ' + httpCode + ')' : ''}\n*Time*: ${jst} JST\n*Mode*: ${mode}\n*Execution*: ${execUrl}${rawDetail ? '\n*Detail*: ```' + rawDetail + '```' : ''}`
  }
}];
